import jwt
import json
from typing import Dict, Any, Optional

def decode_and_verify_jwt(token: str, secret: str, algorithms: list = None) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes.
    
    Args:
        token (str): The JWT token to decode
        secret (str): The secret used to verify the token
        algorithms (list): List of allowed algorithms (default: ['HS256'])
    
    Returns:
        dict: Decoded token payload and metadata
    
    Raises:
        jwt.InvalidTokenError: If token is invalid
        jwt.ExpiredSignatureError: If token has expired
        jwt.DecodeError: If token cannot be decoded
    """
    if algorithms is None:
        algorithms = ['HS256']
    
    try:
        # Decode and verify the token
        payload = jwt.decode(
            token,
            secret,
            algorithms=algorithms,
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'verify_aud': False,
                'verify_iss': False
            }
        )
        
        # Get header information
        header = jwt.get_unverified_header(token)
        
        return {
            'header': header,
            'payload': payload,
            'valid': True
        }
        
    except jwt.ExpiredSignatureError:
        # Get payload even if expired for debugging
        try:
            payload = jwt.decode(
                token,
                secret,
                algorithms=algorithms,
                options={
                    'verify_signature': True,
                    'verify_exp': False,
                    'verify_nbf': True,
                    'verify_iat': True,
                    'verify_aud': False,
                    'verify_iss': False
                }
            )
            return {
                'header': jwt.get_unverified_header(token),
                'payload': payload,
                'valid': False,
                'error': 'Token has expired'
            }
        except Exception:
            raise jwt.InvalidTokenError("Invalid token")
            
    except jwt.InvalidTokenError as e:
        raise jwt.InvalidTokenError(f"Invalid token: {str(e)}")
    except Exception as e:
        raise jwt.DecodeError(f"Failed to decode token: {str(e)}")

def print_jwt_debug_info(token: str, secret: str) -> None:
    """
    Print formatted debug information for JWT token.
    
    Args:
        token (str): The JWT token to debug
        secret (str): The secret used to verify the token
    """
    try:
        result = decode_and_verify_jwt(token, secret)
        print("=== JWT DEBUG INFO ===")
        print(f"Header: {json.dumps(result['header'], indent=2)}")
        print(f"Payload: {json.dumps(result['payload'], indent=2)}")
        print(f"Valid: {result['valid']}")
        if not result['valid'] and 'error' in result:
            print(f"Error: {result['error']}")
        print("======================")
    except Exception as e:
        print(f"Error decoding token: {e}")